+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { allocateEntity, releaseEntity } from '../entity/utils/entity-index';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import type { World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Buffer = { commands: Command[]; spawned: Set<Entity>; destroyed: Set<Entity> };
+
+export type DeferredWorld = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, pair: RelationPair): void;
+    flush(): void;
+};
+
+function makeBuffer(): Buffer {
+    return { commands: [], spawned: new Set(), destroyed: new Set() };
+}
+
+/** Command buffer used by World.  Kept deliberately small: mutation code stays in trait/entity. */
+export function createDeferred(world: World): DeferredWorld {
+    const buffers: Buffer[] = [makeBuffer()];
+    const current = () => buffers[buffers.length - 1];
+
+    const deferred: DeferredWorld = {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            // It is addressable immediately, but is not inserted into queries until flushed.
+            world[$internal].entityTraits.set(entity, new Set());
+            const buffer = current();
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            const buffer = current();
+            buffer.destroyed.add(entity);
+            buffer.commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            current().commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            current().commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            current().commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushBuffer(world, current());
+        },
+    };
+
+    // Internal scope hooks are intentionally non-enumerable implementation detail.
+    Object.defineProperties(deferred, {
+        _enter: { value: () => buffers.push(makeBuffer()) },
+        _exit: { value: () => flushBuffer(world, buffers.pop()!) },
+        _pending: { value: (entity: Entity) => buffers.some((b) => b.commands.some((c) => c.entity === entity)) },
+        _alive: { value: (entity: Entity) => !buffers.some((b) => b.destroyed.has(entity)) },
+    });
+    return deferred;
+}
+
+export function enterDeferredScope(world: World) {
+    (world.deferred as any)._enter();
+}
+export function exitDeferredScope(world: World) {
+    (world.deferred as any)._exit();
+}
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    if ((world.deferred as any)._pending(entity)) world.deferred.flush();
+}
+export function isDeferredEntityAlive(world: World, entity: Entity) {
+    return (world.deferred as any)._alive(entity);
+}
+
+function flushBuffer(world: World, buffer: Buffer) {
+    // Commands scheduled by callbacks during a flush belong to the same buffer.
+    while (buffer.commands.length) {
+        const commands = buffer.commands.splice(0);
+        for (const command of commands) {
+            if (command.type === 'spawn') {
+                if (buffer.destroyed.has(command.entity)) continue;
+                addTrait(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (command.type === 'destroy') {
+                if (buffer.spawned.has(command.entity)) {
+                    // A never-flushed spawn has no query or trait side effects to clean up.
+                    releaseEntity(world[$internal].entityIndex, command.entity);
+                    world[$internal].entityTraits.delete(command.entity);
+                    continue;
+                }
+                if (command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed through a deferred command.');
+                }
+                if (world.has(command.entity)) command.entity.destroy();
+                continue;
+            }
+            // Destroyed entities, including a spawn-destroy pair, consume remaining commands.
+            if (buffer.destroyed.has(command.entity) || !world.has(command.entity)) continue;
+            if (command.type === 'add') addTrait(world, command.entity, ...command.traits);
+            else if (command.type === 'remove') removeTrait(world, command.entity, ...command.traits);
+            else {
+                const relation = command.pair[$internal].relation;
+                removeTrait(world, command.entity, relation('*'));
+                if (command.pair[$internal].target !== '*') addTrait(world, command.entity, command.pair);
+            }
+        }
+    }
+    buffer.destroyed.clear();
+    buffer.spawned.clear();
+}
+
+/** Reads are projected for the common pending add/remove case without forcing a flush. */
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
+    const deferred: any = world.deferred;
+    // A destroyed entity has precisely the post-flush observable state.
+    if (!deferred._alive(entity)) return undefined;
+    return getTrait(world, entity, trait);
+}
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair) {
+    return getDeferredTrait(world, entity, trait) !== undefined || hasTrait(world, entity, isRelationPair(trait) ? trait[$internal].relation[$internal].trait : trait as Trait);
+}
